import glob,re,difflib
files=sorted(glob.glob('ocr2/f_*.txt'))
def norm(l):
    return re.sub(r'\s+',' ',l.strip())
def key(l):
    return re.sub(r'[^a-z0-9]','',l.lower())
def load(f):
    lines=[]
    for raw in open(f,encoding='utf-8',errors='replace'):
        l=raw.rstrip('\n')
        n=norm(l)
        if n=='': continue
        # drop status bar lines
        if re.search(r'Score[:.]',n) and re.search(r'Moves',n): continue
        lines.append(n)
    return lines
def sim(a,b):
    ka,kb=key(a),key(b)
    if ka==kb: return 1.0
    if not ka and not kb: return 1.0
    return difflib.SequenceMatcher(None,ka,kb).ratio()
G=[]
for f in files:
    F=load(f)
    if not F: continue
    if not G:
        G=F[:]; continue
    # find smallest s (new lines at bottom) s.t. F[:len(F)-s] matches tail of G
    best=None
    n=len(F)
    for s in range(0,n+1):
        ov=n-s
        if ov==0:
            best=s; break
        if ov>len(G): continue
        tail=G[-ov:]
        head=F[:ov]
        # compute avg sim
        good=sum(1 for a,b in zip(tail,head) if sim(a,b)>=0.75)
        if good>=ov*0.85:
            best=s; break
    if best is None:
        # no overlap found, treat whole frame as new (append with marker)
        G+= ['<<GAP>>']+F
    else:
        if best>0:
            G+=F[-best:]
print(len(G))
open('/tmp/transcript.txt','w').write('\n'.join(G))
