import glob,re,difflib
from collections import defaultdict
files=sorted(glob.glob('ocr2/f_*.txt'))
def norm(l): return re.sub(r'\s+',' ',l.strip())
def clean_cmd(s):
    s=s.strip()
    s=s.lstrip('>').strip()
    s=re.sub(r'[_\s]+$','',s)   # trailing cursor
    s=s.rstrip('.').strip()
    return s
def frame_cmds(f):
    out=[]
    for raw in open(f,encoding='utf-8',errors='replace'):
        n=norm(raw.rstrip('\n'))
        if not n: continue
        if re.search(r'Score',n) and re.search(r'Moves',n): continue
        if n.startswith('>'):
            c=clean_cmd(n)
            if c!='':
                out.append(c)
    return out
def key(s): return re.sub(r'[^a-z0-9]','',s.lower())
G=[];Gk=[];prev=0
for f in files:
    C=frame_cmds(f)
    if not C: continue
    Ck=[key(x) for x in C]
    if not G:
        G=C[:];Gk=Ck[:];continue
    sm=difflib.SequenceMatcher(None,Gk,Ck,autojunk=False)
    votes=defaultdict(int)
    for a,b,n in sm.get_matching_blocks():
        if n>0:
            o=a-b
            if o>=prev-1 and o<=len(G): votes[o]+=n
    if not votes:
        # relax monotonic
        for a,b,n in sm.get_matching_blocks():
            if n>0 and a-b<=len(G): votes[a-b]+=n
        if not votes: continue
    off=max(votes,key=lambda o:(votes[o],o));prev=max(prev,off)
    j=len(G)-off
    if j<len(C):
        G+=C[max(j,0):];Gk+=Ck[max(j,0):]
for i,c in enumerate(G): print(i+1,repr(c))
print('TOTAL',len(G))
